## الشفرة
```python
def histogram(test):
    # تجزئة السلسلة إلى كلمات وإزالة الفراغات
    words = test.replace(' ', '')

    # إذا كانت السلسلة فارغة، إرجاع قاموس فارغ
    if not words:
        return {}

    # عد تكرار كل حرف
    letter_count = {}
    for letter in words:
        if letter in letter_count:
            letter_count[letter] += 1
        else:
            letter_count[letter] = 1

    # العثور على الحد الأقصى للتكرار
    max_count = max(letter_count.values())

    # إنشاء القاموس للحروف التي لها أعلى تكرار
    result = {letter: count for letter, count in letter_count.items() if count == max_count}

    return result
```

