def is_multiply_prime(a):
    """تحقق مما إذا كان العدد a يمكن التعبير عنه كنتاج ثلاثة أعداد أولية."""
    for i in range(2, int(a**0.5) + 1):
        if a % i == 0 and is_prime(i):
            remaining = a // i
            for j in range(i, int(remaining**0.5) + 1):
                if remaining % j == 0 and is_prime(j):
                    return is_prime(remaining // j)
    return False

